#include <algorithm>
using namespace std;

class Codechef {

    static pair<int, int> solve(houseNode* node) {
        if (!node) return {0, 0};

        auto left = solve(node->leftChild);
        auto right = solve(node->rightChild);

        // Rob this node → skip children
        int rob = node->houseValue + left.second + right.second;

        // Do not rob → children choose best
        int notRob = max(left.first, left.second)
                   + max(right.first, right.second);

        return {rob, notRob};
    }

public:
    static int calculateMaxRob(houseNode* rootHouse) {
        auto ans = solve(rootHouse);
        return max(ans.first, ans.second);
    }
};

