#include <stdio.h>

typedef struct Pair {
    int rob;
    int notRob;
} Pair;

int max(int a, int b) {
    return (a > b) ? a : b;
}

Pair solve(houseNode* node) {

    Pair res;

    if (node == NULL) {
        res.rob = 0;
        res.notRob = 0;
        return res;
    }

    Pair left = solve(node->leftChild);
    Pair right = solve(node->rightChild);

    // Rob this node → skip children
    res.rob = node->houseValue + left.notRob + right.notRob;

    // Do not rob → children choose best
    res.notRob = max(left.rob, left.notRob)
               + max(right.rob, right.notRob);

    return res;
}

int calculateMaxRob(houseNode* rootHouse)
{
    Pair ans = solve(rootHouse);
    return max(ans.rob, ans.notRob);
}

code.Java:
class Codechef {

    static class Pair {
        int rob;
        int notRob;

        Pair(int rob, int notRob) {
            this.rob = rob;
            this.notRob = notRob;
        }
    }

    static Pair solve(houseNode node) {
        if (node == null) return new Pair(0, 0);

        Pair left = solve(node.leftChild);
        Pair right = solve(node.rightChild);

        int rob = node.houseValue + left.notRob + right.notRob;
        int notRob = Math.max(left.rob, left.notRob)
                   + Math.max(right.rob, right.notRob);

        return new Pair(rob, notRob);
    }

    public static int calculateMaxRob(houseNode rootHouse) {
        Pair ans = solve(rootHouse);
        return Math.max(ans.rob, ans.notRob);
    }
}

