class Codechef {
    static calculateMaxRob(rootHouse) {

        function dfs(node) {
            if (node === null) {
                return [0, 0]; // [skip, rob]
            }

            const [ls, lr] = dfs(node.leftChild);
            const [rs, rr] = dfs(node.rightChild);

            const rob = node.houseValue + ls + rs;
            const skip = Math.max(ls, lr) + Math.max(rs, rr);

            return [skip, rob];
        }

        const res = dfs(rootHouse);
        return Math.max(res[0], res[1]);
    }
}
